func newWatchCmd(flags *rootFlags) *cobra.Command {
	var interval time.Duration
	var once bool
	var filter string
	cmd := &cobra.Command{
		Use:   "watch",
		Short: "Poll Gmail history and emit ndjson events",
		Annotations: map[string]string{
			"mcp:read-only": "true",
			"pp:endpoint":   "watch",
		},
		RunE: func(cmd *cobra.Command, args []string) error {
			if interval <= 0 {
				return usageErr(fmt.Errorf("watch: --interval must be greater than 0"))
			}
			return runWatch(cmd, flags, interval, once, filter)
		},
	}
	cmd.Flags().DurationVar(&interval, "interval", 30*time.Second, "Polling interval")
	cmd.Flags().BoolVar(&once, "once", false, "Poll once and exit")
	cmd.Flags().StringVar(&filter, "filter", "", "Event label filter such as label:INBOX")
	return cmd
}

func runWatch(cmd *cobra.Command, flags *rootFlags, interval time.Duration, once bool, filter string) error {
	acct, err := resolveActiveAccount(flags)
	if err != nil {
		return authErr(fmt.Errorf("watch: %w", err))
	}
	db, err := store.OpenWithContext(cmd.Context(), defaultDBPath("superhuman-pp-cli"))
	if err != nil {
		return fmt.Errorf("opening local database: %w", err)
	}
	defer db.Close()
	gc := gmail.New(acct.Store, acct.Email, acct.GoogleID, acct.AccessToken)
	gc.Stderr = cmd.ErrOrStderr()

	for {
		state, err := db.GetHistoryState(cmd.Context(), acct.Email)
		if err != nil {
			return err
		}
		if state == nil || state.LastHistoryID == "" {
			return usageErr(fmt.Errorf("watch: no Gmail history checkpoint; run bootstrap first"))
		}
		// ListHistoryAll walks pagination; ListHistory alone would drop
		// pages 2+ permanently because the checkpoint advances past them.
		delta, err := gc.ListHistoryAll(cmd.Context(), state.LastHistoryID)
		if err != nil {
			if gmail.IsHistoryExpired(err) {
				fmt.Fprintln(cmd.ErrOrStderr(), "watch: history expired; run bootstrap to reset the checkpoint")
				if once {
					return nil
				}
			} else {
				return apiErr(fmt.Errorf("watch: %w", err))
			}
		} else {
			if err := emitWatchEvents(cmd, delta, filter); err != nil {
				return err
			}
			if _, err := db.ApplyHistoryDelta(cmd.Context(), delta); err != nil {
				return err
			}
		}
		if once {
			return nil
		}
		select {
		case <-cmd.Context().Done():
			return nil
		case <-time.After(interval):
		}
	}
}

// PATCH(greptile-watch-filter-symmetry): apply --filter to every event
// type symmetrically. The prior implementation filtered message_added and
// label_added but emitted message_deleted and label_removed unconditionally,
// so an agent watching --filter label:INBOX would receive delete/archive
// events from every other folder. The four cases now filter against the
// most-relevant label set:
//
//   - message_added:   message's current labels (after the add)
//   - message_deleted: message's labels at delete time (Gmail history
//                      records carry them)
//   - label_added:     the added label set
//   - label_removed:   the removed label set (so removing INBOX matches a
//                      --filter label:INBOX watcher's archive interest;
//                      removing STARRED matches a STARRED watcher)
func emitWatchEvents(cmd *cobra.Command, delta *gmail.HistoryResponse, filter string) error {
	enc := json.NewEncoder(cmd.OutOrStdout())
	for _, record := range delta.History {
		for _, added := range record.MessagesAdded {
			if !watchEventMatchesFilter(added.Message.LabelIDs, filter) {
				continue
			}
			if err := enc.Encode(map[string]any{
				"event":      "message_added",
				"message_id": added.Message.ID,
				"thread_id":  added.Message.ThreadID,
				"history_id": record.ID,
			}); err != nil {
				return err
			}
		}
		for _, deleted := range record.MessagesDeleted {
			if !watchEventMatchesFilter(deleted.Message.LabelIDs, filter) {
				continue
			}
			if err := enc.Encode(map[string]any{
				"event":      "message_deleted",
				"message_id": deleted.Message.ID,
				"thread_id":  deleted.Message.ThreadID,
				"history_id": record.ID,
			}); err != nil {
				return err
			}
		}
		for _, change := range record.LabelsAdded {
			if !watchEventMatchesFilter(change.LabelIDs, filter) {
				continue
			}
			for _, label := range change.LabelIDs {
				if err := enc.Encode(map[string]any{
					"event":      "label_added",
					"message_id": change.Message.ID,
					"thread_id":  change.Message.ThreadID,
					"label":      label,
					"history_id": record.ID,
				}); err != nil {
					return err
				}
			}
		}
		for _, change := range record.LabelsRemoved {
			if !watchEventMatchesFilter(change.LabelIDs, filter) {
				continue
			}
			for _, label := range change.LabelIDs {
				event := "label_removed"
				if strings.EqualFold(label, "INBOX") {
					event = "thread_archived"
				}
				if err := enc.Encode(map[string]any{
					"event":      event,
					"message_id": change.Message.ID,
					"thread_id":  change.Message.ThreadID,
					"label":      label,
					"history_id": record.ID,
				}); err != nil {
					return err
				}
			}
		}
	}
	return nil
}

func watchEventMatchesFilter(labels []string, filter string) bool {
	filter = strings.TrimSpace(filter)
	if filter == "" {
		return true
	}
	if strings.HasPrefix(strings.ToLower(filter), "label:") {
		want := strings.TrimSpace(strings.TrimPrefix(strings.ToLower(filter), "label:"))
		return watchLabelsContain(labels, want)
	}
	return true
}

func watchLabelsContain(labels []string, want string) bool {
	for _, label := range labels {
		if strings.EqualFold(label, want) {
			return true
		}
	}
	return false
}
